import{_ as e,o,c as r,a0 as a}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Permission Problems","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/permissions.md","filePath":"troubleshooting/permissions.md"}'),n={name:"troubleshooting/permissions.md"};function d(s,t,i,l,u,c){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="permission-problems" tabindex="-1">Permission Problems <a class="header-anchor" href="#permission-problems" aria-label="Permalink to &quot;Permission Problems&quot;">​</a></h1><p>Use this page as a quick lookup when the app blocks an action. Read the left column first, then match it to the likely cause and the right next step.</p><table tabindex="0"><thead><tr><th>What you see</th><th>Likely cause</th><th>What to do / who to ask</th></tr></thead><tbody><tr><td>A menu item is simply <strong>not there</strong></td><td>Your role does not include that area</td><td>Nothing is broken. Check <a href="./../roles/overview.html">Roles Explained</a>. If you truly need it, ask the next role up.</td></tr><tr><td>An <strong>access denied</strong> or forbidden page</td><td>You opened a page your role cannot use, often from an old bookmark</td><td>Go back to <a href="./../getting-started/dashboard-tour.html">Reading the Dashboard</a> or the sidebar. If you think the role is wrong, ask your King or Supreme Admin.</td></tr><tr><td><strong>&quot;You cannot delete your own account.&quot;</strong></td><td>Self-delete is blocked on purpose</td><td>Ask another admin to handle the account if it really must be removed. See <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</td></tr><tr><td><strong>&quot;At least one active supreme admin must remain.&quot;</strong></td><td>Someone tried to remove, deactivate, or demote the last active Supreme Admin</td><td>Add another active Supreme Admin first. Then retry.</td></tr><tr><td><strong>&quot;You cannot remove your own role because it would lock you out.&quot;</strong></td><td>You tried to remove your own last critical role</td><td>Have another admin make the change, or add another suitable role first.</td></tr><tr><td><strong>&quot;You can only delete users that you created.&quot;</strong></td><td>A King tried to delete a user outside their ownership boundary</td><td>Ask the Supreme Admin to handle it.</td></tr><tr><td><strong>&quot;Cannot delete supreme admin users.&quot;</strong></td><td>A King tried to delete a Supreme Admin</td><td>Only the proper senior admin flow can handle that account. Stop and escalate.</td></tr><tr><td><strong>&quot;You cannot delete users who registered independently.&quot;</strong></td><td>A King tried to delete a self-registered user</td><td>Ask the Supreme Admin to review it instead.</td></tr><tr><td><code>KINGDOM_SCOPE_DENIED</code></td><td>An alliance-scoped role tried to use a kingdom-scoped action</td><td>Check your <a href="./../getting-started/navigating.html">context banner</a>. If the action really is kingdom-level, ask your King or Supreme Admin.</td></tr><tr><td><code>USAGE_SCOPE_DENIED</code></td><td>You tried to view usage outside your own scope</td><td>Open the correct kingdom or alliance first. If you still cannot see it, your role does not cover that scope.</td></tr><tr><td><strong>&quot;Only PNG, JPEG, or WebP image uploads are supported&quot;</strong> or <code>INVALID_UPLOAD_TYPE</code></td><td>The upload is not a supported image type</td><td>Re-export the file as PNG, JPEG, or WebP, then try again. See <a href="./../imports/upload-screenshots.html">Upload Screenshots</a>.</td></tr><tr><td><strong>&quot;This event instance is locked. Request unlock or ask a leader to unlock it.&quot;</strong> or <code>INSTANCE_LOCKED</code></td><td>The event instance auto-locked after the cleanup window</td><td>Use <a href="./../how-to/session-lock.html">Locked Instances &amp; Unlock Requests</a>.</td></tr><tr><td><code>KINGDOM_ALLIANCE_GRANT_LIMIT_REACHED</code></td><td>The kingdom plan does not have any grant slots left</td><td>Review the current grant usage on the kingdom side. See <a href="./../subscriptions/kingdom-grants.html">Grant Premium to Your Alliances</a>.</td></tr><tr><td><code>ALLOCATION_EXCEEDS_KINGDOM_QUOTA</code></td><td>The allocation total is higher than the kingdom plan allows</td><td>Reduce the allocation or raise the kingdom limit first. See <a href="./../subscriptions/allocations.html">Share Kingdom Quotas with Alliances</a>.</td></tr><tr><td><strong>&quot;Only alliances with a pending or accepted kingdom subscription grant can receive an allocation.&quot;</strong> or <code>ALLIANCE_NOT_GRANTED</code></td><td>An allocation was attempted for an alliance that does not currently hold a grant</td><td>Offer or re-activate the grant first. Then return to the allocation step.</td></tr><tr><td><strong>&quot;Quota limits were reached. New writes are blocked until old resources are cleaned up or additional capacity is granted.&quot;</strong></td><td>A hard limit was reached</td><td>Use <a href="./quotas.html">Quota &amp; Suspension Problems</a> and <a href="./../subscriptions/cleanup.html">Run a Cleanup</a>.</td></tr><tr><td><strong>&quot;Limited cleanup mode is active. New writes are blocked while cleanup actions remain available.&quot;</strong></td><td>The scope is in limited mode because usage reached a hard limit</td><td>Cleanup is still allowed. Use <a href="./quotas.html">Quota &amp; Suspension Problems</a>.</td></tr></tbody></table><h2 id="if-you-are-still-unsure" tabindex="-1">If you are still unsure <a class="header-anchor" href="#if-you-are-still-unsure" aria-label="Permalink to &quot;If you are still unsure&quot;">​</a></h2><ol><li>Check <a href="./../getting-started/navigating.html">Finding Your Way Around</a> and confirm the current context.</li><li>Check <a href="./../roles/overview.html">Roles Explained</a> and make sure the action belongs to your role.</li><li>If the message is one of the safety rules above, do not try to work around it. Ask the correct higher role instead.</li></ol>',5)])])}const p=e(n,[["render",d]]);export{m as __pageData,p as default};
